key.definition:
syntax = "proto3";
package inventory.app.public.customers;

message Key {
  int64 customer_id = 142711320;
}

value.definition:
syntax = "proto3";
package inventory.app.public.customers;

message Envelope {
  message Value {
    message Field_customer_id {
      oneof state {
        int64 value = 1;
        string unavailable = 2;
        string text = 3;
      }
    }
    message Field_name {
      oneof state {
        string value = 1;
        string unavailable = 2;
      }
    }
    message Field_unsigned_value {
      oneof state {
        uint64 value = 1;
        string unavailable = 2;
        string text = 3;
      }
    }
    message Field_score {
      oneof state {
        double value = 1;
        string unavailable = 2;
        string text = 3;
      }
    }
    message Field_binary_value {
      oneof state {
        bytes value = 1;
        string unavailable = 2;
        string text = 3;
      }
    }
    message Field_counter {
      oneof state {
        int32 value = 1;
        string unavailable = 2;
        string text = 3;
      }
    }
    message Field_tags {
      message NativeValue {
        message Item {
          oneof state {
            string value = 1;
            bool null_value = 2;
            string unavailable = 3;
          }
        }
        repeated Item values = 1;
      }
      oneof state {
        NativeValue value = 1;
        string unavailable = 2;
        string text = 3;
      }
    }
    message Field_matrix {
      message NativeValue {
        message Item {
          message NativeValue {
            message Item {
              oneof state {
                int32 value = 1;
                bool null_value = 2;
                string unavailable = 3;
                string text = 4;
              }
            }
            repeated Item values = 1;
          }
          oneof state {
            NativeValue value = 1;
            bool null_value = 2;
            string unavailable = 3;
            string text = 4;
          }
        }
        repeated Item values = 1;
      }
      oneof state {
        NativeValue value = 1;
        string unavailable = 2;
        string text = 3;
      }
    }
    message Field_attributes {
      message NativeValue {
        message EntryValue {
          oneof state {
            string value = 1;
            bool null_value = 2;
            string unavailable = 3;
          }
        }
        map<string, EntryValue> values = 1;
      }
      oneof state {
        NativeValue value = 1;
        string unavailable = 2;
        string text = 3;
      }
    }
    Field_customer_id customer_id = 142711320;
    Field_name name = 44258180;
    Field_unsigned_value unsigned_value = 510467060;
    Field_score score = 91600798;
    Field_binary_value binary_value = 476827019;
    Field_counter counter = 266901967;
    Field_tags tags = 395063182;
    Field_matrix matrix = 234933594;
    Field_attributes attributes = 297065278;
  }
  message Source {
    string version = 1;
    string connector = 2;
    string name = 3;
    optional int64 ts_ms = 4;
    string snapshot = 5;
    string db = 6;
    optional string schema = 7;
    optional string table = 8;
    string sequence = 20;
    optional uint32 txId = 21;
    uint64 lsn = 22;
    optional int64 xmin = 23;
  }
  message Transaction {
    string id = 1;
    optional uint64 total_order = 2;
    optional uint64 data_collection_order = 3;
  }
  Value before = 1;
  Value after = 2;
  Source source = 3;
  string op = 4;
  int64 ts_ms = 5;
  Transaction transaction = 6;
}
